"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { getDashboardPathForRole } from "../../../lib/auth";

export default function GovernmentDashboard() {
  const [data, setData] = useState<any[]>([]);
  const [disease, setDisease] = useState("");
  const router = useRouter();

  useEffect(() => {
    const stored = localStorage.getItem("user");

    if (!stored) {
      router.replace("/auth/login");
      return;
    }

    const user = JSON.parse(stored);

    // Only GOVERNMENT users can access this dashboard
    if (user.role !== "GOVERNMENT") {
      const target = getDashboardPathForRole(user.role);
      router.replace(target);
    }
  }, []);

  const fetchAnalytics = async () => {
    const res = await fetch(
      `http://localhost:5000/api/government/analytics?disease=${disease}`,
      {
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
      }
    );

    const result = await res.json();
    setData(result);
  };

  return (
    <div>
      <h1 className="text-xl font-bold mb-4">Government Dashboard</h1>

      <div className="bg-white p-4 rounded shadow mb-4">
        <input
          placeholder="Filter by disease"
          value={disease}
          onChange={(e) => setDisease(e.target.value)}
          className="border p-2 mr-2"
        />
        <button
          onClick={fetchAnalytics}
          className="bg-green-600 text-white px-4 py-2 rounded"
        >
          Search
        </button>
      </div>

      <div className="space-y-3">
        {data.map((item, i) => (
          <div key={i} className="bg-white p-3 rounded shadow">
            <p><strong>Disease:</strong> {item._id.disease}</p>
            <p><strong>Location:</strong> {item._id.location}</p>
            <p><strong>Cases:</strong> {item.count}</p>
          </div>
        ))}
      </div>
    </div>
  );
}